/**
 * UpdateEventBlockRequest
 *
 * Status transitions and field corrections for an event block.
 *
 * All fields except event_id are optional — only supplied fields are updated.
 */
export type UpdateEventBlockRequest = {
    /**
     * Event Id
     *
     * Target event ID.
     */
    event_id: string;
    /**
     * Transition To
     *
     * Status transition. Valid moves depend on current status: captured → committed | voided | superseded; classified → committed | pending | fulfilled | voided | superseded; committed → pending | fulfilled | voided | superseded; pending → fulfilled | voided | superseded. Terminal states (fulfilled, voided, superseded) accept no further transitions. Note: classified and fulfilled are usually set by handlers, not by callers, but the transition is allowed for corrections.
     */
    transition_to?: 'committed' | 'pending' | 'fulfilled' | 'voided' | 'superseded' | null;
    /**
     * Superseded By Id
     *
     * New event id that replaces this one. Required when transition_to='superseded'.
     */
    superseded_by_id?: string | null;
    /**
     * Description
     *
     * Replacement free-text summary. Unset = unchanged; pass an empty string to clear.
     */
    description?: string | null;
    /**
     * Effective At
     *
     * New accounting recognition date. Unset = unchanged. Useful when an event was captured against the wrong period.
     */
    effective_at?: string | null;
    /**
     * Metadata Patch
     *
     * Key-value pairs merged into existing metadata (additive patch, not replace).
     */
    metadata_patch?: {
        [key: string]: unknown;
    };
    /**
     * Obligated By Event Id
     *
     * Set/update the forward-materialization link.
     */
    obligated_by_event_id?: string | null;
    /**
     * Discharges Event Id
     *
     * Set/update the settlement link.
     */
    discharges_event_id?: string | null;
};

